bomData.valueScript:
try {
    // Parse the json string
    const hardwareElements = JSON.parse(part.pa_BomId) as { values: string[] };

    // Check if the json got a valid format
    if (!Array.isArray(hardwareElements.values)) {
      throw new Error("Could not create the BOM for the fliplift fittings");
    }

    // Iterate throug the hardware elements
    for (const value of hardwareElements.values) {

      // Check if we should add an entry
      if (value !== "None") {

        // Query the hardware mapping table
        let hardwareID = GlobalFunc.find_HardwareLibraryMapping(value);

        // Iterate through all the found hardware items
        hardwareID.forEach((elem) => {

          // Retrieve the hardware data from the hardware library
          let HardwareInfo = GlobalFunc.find_HardwareLibrary(elem.SupplierArticleNumber!, elem.Supplier!);

          // Add the BOM element
          let HardwareElem = this.addbomout_Hardware();
          HardwareElem.bom_Supplier = HardwareInfo.in_Supplier;
          HardwareElem.bom_SupplierArticle = HardwareInfo.in_SupplierArticleNumber;
          HardwareElem.bom_Description1 = HardwareInfo.Description;
          HardwareElem.bom_Description2 = HardwareInfo.Description2;
          HardwareElem.bom_Color = HardwareInfo.Color;
          HardwareElem.bom_ElementCategory = HardwareInfo.Category;
          HardwareElem.bom_Length = HardwareInfo.Length;
          HardwareElem.bom_Width = HardwareInfo.Width;
          HardwareElem.bom_Thk = HardwareInfo.Thickness;
        });
      }
    }
  }

  // Catch the errors
  catch (error: any) {
    logError(error.Message);
    return
  }
